{
  "verses": [
    {
      "n": 4,
      "column": "left",
      "text": "Irr tew tahds Elkons/ ka\ntam STIPRAM DEE-\nWAM? mahki tu ar tahdu\nBalsi Pehrkonus islaist/ ka\nwiꞥſch?\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Puschkoojes jelle ar Gref-\nnibu un Angstibu/ un apgehr-\nbees ar leelu Gohdu un Gohdibn.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Iskatſi tawas Dufmibas\nBahrsibu/ un usluhko wiꞥſch wisſus\nLepnos/ un pasemmo tohs.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Usluhko wiꞥſch Lepnos/ un\npahrwaldi tohs/ un fatreez tohs\nBesdeewigus winnu Weetâ.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Apslep tohs kohpa eekſch\nBihschleem/ un gahs winnu Bai-\nns Sleppeniba.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Tad es tew arridsan teik-\nchu/ ka tawa labba Rohka tew\nalihdseht warr.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Raugi nu/ tas Beëmots/\no es fahnis tew efmu darrigs/\nhd Scenu ka Wehrfis.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Usluhko jelle/ winna\nSpehks irr eekſch winna Gur-\neem/ unn winna Stiprums\nkfch winna Wehdera Nabbas.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Wiꞥſch kustina fanu A-\nn ka Zeedra. Kohku/ winna\nannuma Dsihsles irr zaur ween\ntrru fapihtas.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Winna Kauli irr ka zeets\nBarsch/ winna Lohzekti ka Dsel-\nS Meeti.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Wiꞥſch irr ta STIP-\nA DEEWA Zeltu Eesah-\nms/ kas winnu irr darrigs/tas\ninnu aisfare ar fanu Sohbinn.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Tapchz ka tee Kalni win-\nnam Barribu iswedd/ tad spehle\nwiꞥſch Lauka Swehri tur.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Starp to Kohku Paëhni\nwinſch apgullahs/ Needrês un\nDubtôs apslehpts.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "To Kohku Paëhnis ap-\nfeds winnu ar fanu Ehnu/ tas\nKahrklis pee Uppes apklahj\nwinnu.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Rangi/ winſch eerihj to\nuppi ar Warru/ un ne dauds\nsteidsahs/ winſch tchkeetahs to\nJardanu ar fanu Mutti isfmelt.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Warrig winnu meddiht\nta ka winſch to reds? warrig ar\nWirwehm winnam to Deggonu\nzaur urbt?\n"
    },
    {
      "n": 20,
      "column": "right",
      "text": "Arri tu to Lewijatanu\nar weenu Makschkerti\nsweiioht/ jeb winna\nMehli ar weenu dsilki eemestu\nWirwi?\n"
    },
    {
      "n": 21,
      "column": "right",
      "text": "Mahki tu winnam wee-\nnu Rinki eekſch Nahsim lift/ unn\nar Asinini winna Schaunas is-\nurbt?\n"
    },
    {
      "n": 22,
      "column": "right",
      "text": "Woj tu dohma/ ka tas\ntew dauds peeluhgs/ unn labbus\nWahrdus us tew runnahs?\n"
    },
    {
      "n": 23,
      "column": "right",
      "text": "Darrihs winſch weenu\nDerribu ar tewi/ ka tu winnu\npar muhschigu Wehrgu nemt\nwarri?\n"
    },
    {
      "n": 24,
      "column": "right",
      "text": "Warrefi tu ar winnu\nspebleht/ itt ka ar Putminu? jeb\nNnnnnn\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
